/* Number of distinct literal/length and distance symbols in DEFLATE */
#define ZOPFLI_NUM_LL 288

#define ZOPFLI_NUM_D 32

typedef struct SymbolStats
{
    /* The literal and length symbols. */
    size_t litlens[ZOPFLI_NUM_LL];
    /* The 32 unique dist symbols, not the 32768 possible dists. */
    size_t dists[ZOPFLI_NUM_D];

    /* Length of each lit/len symbol in bits. */
    double ll_symbols[ZOPFLI_NUM_LL];
    /* Length of each dist symbol in bits. */
    double d_symbols[ZOPFLI_NUM_D];
} SymbolStats;

typedef struct RanState
{
    unsigned int m_w, m_z;

static void CalculateStatistics(SymbolStats *stats)
// clang-format off
__CPROVER_requires(__CPROVER_is_fresh(stats, sizeof(*stats)))
__CPROVER_assigns(__CPROVER_object_whole(stats->ll_symbols))
__CPROVER_assigns(__CPROVER_object_whole(stats->d_symbols))
/* Both symbol tables are filled with non-negative entropy contributions. */
__CPROVER_ensures(stats->ll_symbols[0] >= 0)
__CPROVER_ensures(stats->d_symbols[0] >= 0)
// clang-format on
{
    ZopfliCalculateEntropy(stats->litlens, ZOPFLI_NUM_LL, stats->ll_symbols);
    ZopfliCalculateEntropy(stats->dists, ZOPFLI_NUM_D, stats->d_symbols);
}

/* Appends the symbol statistics from the store. */
static void GetStatistics(const ZopfliLZ77Store *store, SymbolStats *stats)
// clang-format off
/* The store header and the two arrays read by the loop (litlens / dists) must
   be valid for the store's whole length. */
__CPROVER_requires(__CPROVER_is_fresh(store, sizeof(*store)))
/* Bound the store length so the byte sizes below cannot overflow size_t when
   sizing the fresh arrays (a soundness condition for is_fresh, not a value tied
   to any CBMC command-line argument). */
__CPROVER_requires(store->size <= ZOPFLI_WINDOW_SIZE)
__CPROVER_requires(__CPROVER_is_fresh(store->litlens, store->size * sizeof(*store->litlens)))
__CPROVER_requires(__CPROVER_is_fresh(store->dists, store->size * sizeof(*store->dists)))
/* Every litlen entry is used either directly as an index into the 288-entry
   stats->litlens table (literal case) or as the argument to
   ZopfliGetLengthSymbol, both of which require it to be a valid DEFLATE length
   in [0, 258]. */
__CPROVER_requires(__CPROVER_forall { size_t k; (k < store->size) ==> store->litlens[k] <= 258 })
/* A non-zero dist is a real DEFLATE distance in [1, 32768] (the argument domain
   of ZopfliGetDistSymbol); a zero dist marks a literal. */
__CPROVER_requires(__CPROVER_forall { size_t kd; (kd < store->size) ==> store->dists[kd] <= 32768 })
/* The statistics object is a fresh, writable SymbolStats. */
__CPROVER_requires(__CPROVER_is_fresh(stats, sizeof(*stats)))
__CPROVER_assigns(__CPROVER_object_whole(stats->litlens))
__CPROVER_assigns(__CPROVER_object_whole(stats->dists))
__CPROVER_assigns(__CPROVER_object_whole(stats->ll_symbols))
__CPROVER_assigns(__CPROVER_object_whole(stats->d_symbols))
/* The end symbol is always recorded exactly once. */
__CPROVER_ensures(stats->litlens[256] == 1)
/* The entropy tables computed from the histogram are non-negative. */
__CPROVER_ensures(stats->ll_symbols[0] >= 0)
__CPROVER_ensures(stats->d_symbols[0] >= 0)
// clang-format on
{
    size_t i;
    for (i = 0; i < store->size; i++)
    {
        if (store->dists[i] == 0)
        {
            stats->litlens[store->litlens[i]]++;
        }
        else
        {
            stats->litlens[ZopfliGetLengthSymbol(store->litlens[i])]++;
            stats->dists[ZopfliGetDistSymbol(store->dists[i])]++;
        }
    }
    stats->litlens[256] = 1; /* End symbol. */

    CalculateStatistics(stats);
}

static void ClearStatFreqs(SymbolStats *stats)
// clang-format off
__CPROVER_requires(__CPROVER_is_fresh(stats, sizeof(*stats)))
__CPROVER_assigns(__CPROVER_object_whole(stats->litlens))
__CPROVER_assigns(__CPROVER_object_whole(stats->dists))

